/**
 * Class to bind a textarea element with Gradio's backend.
 */
class GradioTextAreaBind {
  /**
   * Initializes a binding between a textarea and Gradio.
   * @param {string} elementId - The ID of the target element.
   * @param {string} className - The class name of the target element.
   */
  constructor(elementId, className) {
      this.target = document.querySelector(`#${elementId}.${className} textarea`);
      this.syncLock = false;
      this.previousValue = '';
  }

  /**
   * Sets the value of the textarea and dispatches an input event.
   * @param {string} newValue - The new value to set.
   */
  setValue(newValue) {
      if (this.syncLock) return;

      this.syncLock = true;
      this.target.value = newValue;
      this.previousValue = newValue;

      const inputEvent = new Event('input', { bubbles: true });
      Object.defineProperty(inputEvent, 'target', { value: this.target });
      this.target.dispatchEvent(inputEvent);

      this.syncLock = false;
  }

  /**
   * Listens for changes in the textarea and triggers a callback.
   * @param {Function} callback - The function to call on value change.
   */
  listen(callback) {
      const observer = new MutationObserver(() => {
          if (this.target.value !== this.previousValue) {
              this.previousValue = this.target.value;

              if (this.syncLock) return;

              this.syncLock = true;
              callback(this.target.value);
              this.syncLock = false;
          }
      });

      observer.observe(this.target, { attributes: true, childList: true, subtree: true, characterData: true });
  }
}

/**
* Class to manage a drawing canvas with image manipulation features.
*/
class ForgeCanvas {
  // Initialization functions
  constructor(
      uuid,
      noUpload = false,
      noScribbles = false,
      contrastScribbles = false,
      initialHeight = 512,
      scribbleColor = '#000000',
      scribbleColorFixed = false,
      scribbleWidth = 4,
      scribbleWidthFixed = false,
      scribbleAlpha = 100,
      scribbleAlphaFixed = false,
      scribbleSoftness = 0,
      scribbleSoftnessFixed = false
  ) {
      this.gradioConfig = typeof gradio_config !== 'undefined' ? gradio_config : null; // Ensure gradio_config is defined
      this.uuid = uuid;
      this.noUpload = noUpload;
      this.noScribbles = noScribbles;
      this.contrastScribbles = contrastScribbles;
      this.initialHeight = initialHeight;
      this.img = null;
      this.imgX = 0;
      this.imgY = 0;
      this.originalWidth = 0;
      this.originalHeight = 0;
      this.imgScale = 1;
      this.dragging = false;
      this.draggedJustNow = false;
      this.resizing = false;
      this.drawing = false;
      this.scribbleColor = scribbleColor;
      this.scribbleWidth = scribbleWidth;
      this.scribbleAlpha = scribbleAlpha;
      this.scribbleSoftness = scribbleSoftness;
      this.scribbleColorFixed = scribbleColorFixed;
      this.scribbleWidthFixed = scribbleWidthFixed;
      this.scribbleAlphaFixed = scribbleAlphaFixed;
      this.scribbleSoftnessFixed = scribbleSoftnessFixed;
      this.history = [];
      this.historyIndex = -1;
      this.maximized = false;
      this.originalState = {};
      this.contrastPattern = null;
      this.pointerInsideContainer = false;
      this.tempCanvas = document.createElement('canvas');
      this.tempDrawPoints = [];
      this.tempDrawBackground = null;
      this.backgroundGradioBind = new GradioTextAreaBind(this.uuid, 'logical_image_background');
      this.foregroundGradioBind = new GradioTextAreaBind(this.uuid, 'logical_image_foreground');
      this.drawingPath = new Path2D();
      this.start();
  }

  start() {
      this.initializeElements();
      this.initializeInputValues();
      this.setInitialStyles();
      this.handleFeatureToggles();
      this.observeContainerResizing();
      this.initializeEventListeners();
      this.initializeUndoRedoButtons();
      this.listenForBackgroundAndForegroundChanges();
  }

  initializeElements() {
      this.imageContainer = document.getElementById(`imageContainer_${this.uuid}`);
      this.imageElement = document.getElementById(`image_${this.uuid}`);
      this.resizeLine = document.getElementById(`resizeLine_${this.uuid}`);
      this.container = document.getElementById(`container_${this.uuid}`);
      this.toolbar = document.getElementById(`toolbar_${this.uuid}`);
      this.uploadButton = document.getElementById(`uploadButton_${this.uuid}`);
      this.resetButton = document.getElementById(`resetButton_${this.uuid}`);
      this.centerButton = document.getElementById(`centerButton_${this.uuid}`);
      this.removeButton = document.getElementById(`removeButton_${this.uuid}`);
      this.undoButton = document.getElementById(`undoButton_${this.uuid}`);
      this.redoButton = document.getElementById(`redoButton_${this.uuid}`);
      this.drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      this.maxButton = document.getElementById(`maxButton_${this.uuid}`);
      this.minButton = document.getElementById(`minButton_${this.uuid}`);
      this.scribbleIndicator = document.getElementById(`scribbleIndicator_${this.uuid}`);
      this.uploadHint = document.getElementById(`uploadHint_${this.uuid}`);
      this.scribbleColorInput = document.getElementById(`scribbleColor_${this.uuid}`);
      this.scribbleColorBlock = document.getElementById(`scribbleColorBlock_${this.uuid}`);
      this.scribbleWidthInput = document.getElementById(`scribbleWidth_${this.uuid}`);
      this.widthLabel = document.getElementById(`widthLabel_${this.uuid}`);
      this.scribbleWidthBlock = document.getElementById(`scribbleWidthBlock_${this.uuid}`);
      this.scribbleAlphaInput = document.getElementById(`scribbleAlpha_${this.uuid}`);
      this.alphaLabel = document.getElementById(`alphaLabel_${this.uuid}`);
      this.scribbleAlphaBlock = document.getElementById(`scribbleAlphaBlock_${this.uuid}`);
      this.scribbleSoftnessInput = document.getElementById(`scribbleSoftness_${this.uuid}`);
      this.softnessLabel = document.getElementById(`softnessLabel_${this.uuid}`);
      this.scribbleSoftnessBlock = document.getElementById(`scribbleSoftnessBlock_${this.uuid}`);
      this.imageInput = document.getElementById(`imageInput_${this.uuid}`);
  }

  initializeInputValues() {
      this.scribbleColorInput.value = this.scribbleColor;
      this.scribbleWidthInput.value = this.scribbleWidth;
      this.scribbleAlphaInput.value = this.scribbleAlpha;
      this.scribbleSoftnessInput.value = this.scribbleSoftness;
  }

  setInitialStyles() {
      const scribbleIndicatorSize = this.scribbleWidth * 20;
      this.scribbleIndicator.style.width = `${scribbleIndicatorSize}px`;
      this.scribbleIndicator.style.height = `${scribbleIndicatorSize}px`;
      this.container.style.height = `${this.initialHeight}px`;
      this.drawingCanvas.width = this.imageContainer.clientWidth;
      this.drawingCanvas.height = this.imageContainer.clientHeight;
      this.drawingContext = this.drawingCanvas.getContext('2d', { willReadFrequently: true });
  }

  handleFeatureToggles() {
      if (this.noScribbles) {
          this.toggleScribbleFeatures(false);
      }

      if (this.noUpload) {
          this.uploadButton.style.display = 'none';
          this.uploadHint.style.display = 'none';
      }

      if (this.contrastScribbles) {
          this.createContrastPattern();
      }

      this.adjustUIBasedOnFixedScribbleProperties();
  }

  toggleScribbleFeatures(show) {
      const display = show ? 'block' : 'none';
      this.resetButton.style.display = display;
      this.undoButton.style.display = display;
      this.redoButton.style.display = display;
      this.scribbleColorInput.style.display = display;
      this.scribbleColorBlock.style.display = display;
      this.scribbleWidthBlock.style.display = display;
      this.scribbleAlphaBlock.style.display = display;
      this.scribbleSoftnessBlock.style.display = display;
      this.scribbleIndicator.style.display = display;
      this.drawingCanvas.style.display = display;
  }

  createContrastPattern() {
      this.scribbleColorBlock.style.display = 'none';
      this.scribbleAlphaBlock.style.display = 'none';
      this.scribbleSoftnessBlock.style.display = 'none';

      const patternCanvas = this.tempCanvas;
      patternCanvas.width = 20;
      patternCanvas.height = 20;
      const patternContext = patternCanvas.getContext('2d');
      patternContext.fillStyle = '#ffffff';
      patternContext.fillRect(0, 0, 10, 10);
      patternContext.fillRect(10, 10, 10, 10);
      patternContext.fillStyle = '#000000';
      patternContext.fillRect(10, 0, 10, 10);
      patternContext.fillRect(0, 10, 10, 10);
      this.contrastPattern = this.drawingContext.createPattern(patternCanvas, 'repeat');
      this.drawingCanvas.style.opacity = '0.5';
  }

  adjustUIBasedOnFixedScribbleProperties() {
      if (this.contrastScribbles || (this.scribbleColorFixed && this.scribbleAlphaFixed && this.scribbleSoftnessFixed)) {
          this.scribbleSoftnessBlock.style.width = '100%';
          this.scribbleWidthInput.style.width = '100%';
          this.widthLabel.style.display = 'none';
      }

      if (this.scribbleColorFixed) {
          this.scribbleColorBlock.style.display = 'none';
      }

      if (this.scribbleWidthFixed) {
          this.scribbleWidthBlock.style.display = 'none';
      }

      if (this.scribbleAlphaFixed) {
          this.scribbleAlphaBlock.style.display = 'none';
      }

      if (this.scribbleSoftnessFixed) {
          this.scribbleSoftnessBlock.style.display = 'none';
      }
  }

  observeContainerResizing() {
      const resizeObserver = new ResizeObserver(() => {
          this.adjustInitialPositionAndScale();
          this.drawImage();
      });
      resizeObserver.observe(this.container);
  }

  // Event handling functions
  initializeEventListeners() {
      this.initializeImageInputEvents();
      this.initializeButtonEvents();
      this.initializeScribbleInputEvents();
      this.initializeDrawingCanvasEvents();
      this.initializeImageContainerEvents();
      this.initializeDocumentEvents();
  }

  initializeImageInputEvents() {
      this.imageInput.addEventListener('change', (event) => this.handleFileUpload(event.target.files[0]));
      this.uploadButton.addEventListener('click', () => !this.noUpload && this.imageInput.click());
  }

  initializeButtonEvents() {
      this.resetButton.addEventListener('click', () => this.resetImage());
      this.centerButton.addEventListener('click', () => {
          this.adjustInitialPositionAndScale();
          this.drawImage();
      });
      this.removeButton.addEventListener('click', () => this.removeImage());
      this.undoButton.addEventListener('click', () => this.undo());
      this.redoButton.addEventListener('click', () => this.redo());
      this.maxButton.addEventListener('click', () => this.maximize());
      this.minButton.addEventListener('click', () => this.minimize());
  }

  initializeScribbleInputEvents() {
      this.scribbleColorInput.addEventListener('input', () => {
          this.scribbleColor = this.scribbleColorInput.value;
          this.scribbleIndicator.style.borderColor = this.scribbleColor;
      });
      this.scribbleWidthInput.addEventListener('input', () => {
          this.scribbleWidth = this.scribbleWidthInput.value;
          const newSize = this.scribbleWidth * 20;
          this.scribbleIndicator.style.width = `${newSize}px`;
          this.scribbleIndicator.style.height = `${newSize}px`;
      });
      this.scribbleAlphaInput.addEventListener('input', () => this.scribbleAlpha = this.scribbleAlphaInput.value);
      this.scribbleSoftnessInput.addEventListener('input', () => this.scribbleSoftness = this.scribbleSoftnessInput.value);
  }

  initializeDrawingCanvasEvents() {
    this.drawingCanvas.addEventListener('pointerdown', this.handlePointerEvent.bind(this));
    this.drawingCanvas.addEventListener('pointermove', this.handlePointerEvent.bind(this));
    this.drawingCanvas.addEventListener('pointerup', this.handlePointerEvent.bind(this));
    this.drawingCanvas.addEventListener('pointerleave', this.handlePointerEvent.bind(this));
  }

  handlePointerEvent(event) {
    const rect = this.drawingCanvas.getBoundingClientRect();
    const x = (event.clientX - rect.left) / this.imgScale;
    const y = (event.clientY - rect.top) / this.imgScale;

    switch (event.type) {
      case 'pointerdown':
        if (!this.img || event.button !== 0 || this.noScribbles) return;
        this.drawing = true;
        this.drawingCanvas.style.cursor = 'crosshair';
        this.scribbleIndicator.style.display = 'none';
        this.tempDrawPoints = [[x, y]];
        this.tempDrawBackground = this.drawingContext.getImageData(0, 0, this.drawingCanvas.width, this.drawingCanvas.height);
        this.handleDraw(event);
        break;
      case 'pointermove':
        if (this.drawing) {
          this.handleDraw(event);
        }
        if (this.img && !this.dragging) {
          this.drawingCanvas.style.cursor = 'crosshair';
        }
        if (this.img && !this.dragging && !this.noScribbles) {
          const containerRect = this.imageContainer.getBoundingClientRect();
          const indicatorOffset = this.scribbleWidth * 10;
          this.scribbleIndicator.style.left = `${event.clientX - containerRect.left - indicatorOffset}px`;
          this.scribbleIndicator.style.top = `${event.clientY - containerRect.top - indicatorOffset}px`;
          this.scribbleIndicator.style.display = 'block';
        }
        break;
      case 'pointerup':
      case 'pointerleave':
        if (this.drawing) {
          this.drawing = false;
          this.drawingCanvas.style.cursor = '';
          this.scribbleIndicator.style.display = 'none';
          this.saveState();
        }
        break;
    }
  }

  initializeImageContainerEvents() {
      this.imageContainer.addEventListener('pointerdown', (event) => {
          const rect = this.imageContainer.getBoundingClientRect();
          const offsetX = event.clientX - rect.left;
          const offsetY = event.clientY - rect.top;

          if (event.button === 2 && this.isInsideImage(offsetX, offsetY)) {
              this.dragging = true;
              this.offsetX = offsetX - this.imgX;
              this.offsetY = offsetY - this.imgY;
              this.imageElement.style.cursor = 'grabbing';
              this.drawingCanvas.style.cursor = 'grabbing';
              this.scribbleIndicator.style.display = 'none';
          } else if (event.button === 0 && !this.img && !this.noUpload) {
              this.imageInput.click();
          }
      });

      this.imageContainer.addEventListener('pointermove', (event) => {
          if (this.dragging) {
              const rect = this.imageContainer.getBoundingClientRect();
              const mouseX = event.clientX - rect.left;
              const mouseY = event.clientY - rect.top;

              this.imgX = mouseX - this.offsetX;
              this.imgY = mouseY - this.offsetY;
              this.drawImage();
              this.draggedJustNow = true;
          }
      });

      this.imageContainer.addEventListener('pointerup', (event) => {
          if (this.dragging) {
              this.handleDragEnd(event, false);
          }
      });

      this.imageContainer.addEventListener('pointerleave', (event) => {
          if (this.dragging) {
              this.handleDragEnd(event, true);
          }
      });

      this.imageContainer.addEventListener('wheel', (event) => {
          if (!this.img) return;

          event.preventDefault();

          const rect = this.imageContainer.getBoundingClientRect();
          const mouseX = event.clientX - rect.left;
          const mouseY = event.clientY - rect.top;
          const previousScale = this.imgScale;
          const zoomFactor = event.deltaY * -0.001;

          this.imgScale += zoomFactor;
          this.imgScale = Math.max(0.1, this.imgScale);

          const scaleRatio = this.imgScale / previousScale;
          this.imgX = mouseX - (mouseX - this.imgX) * scaleRatio;
          this.imgY = mouseY - (mouseY - this.imgY) * scaleRatio;

          this.drawImage();
      });

      this.imageContainer.addEventListener('contextmenu', (event) => {
          event.preventDefault();
          this.draggedJustNow = false;
      });

      this.imageContainer.addEventListener('pointerover', () => {
          this.toolbar.style.opacity = '1';
          if (!this.img && !this.noUpload) {
              this.imageContainer.style.cursor = 'pointer';
          }
      });

      this.imageContainer.addEventListener('pointerout', () => {
          this.toolbar.style.opacity = '0';
          this.imageElement.style.cursor = '';
          this.drawingCanvas.style.cursor = '';
          this.imageContainer.style.cursor = '';
          this.scribbleIndicator.style.display = 'none';
      });

      this.resizeLine.addEventListener('pointerdown', (event) => {
          this.resizing = true;
          event.preventDefault();
          event.stopPropagation();
      });
  }

  initializeDocumentEvents() {
      document.addEventListener('pointermove', (event) => {
          if (this.resizing) {
              const containerRect = this.container.getBoundingClientRect();
              const newHeight = event.clientY - containerRect.top;
              this.container.style.height = `${newHeight}px`;
              event.preventDefault();
              event.stopPropagation();
          }
      });

      document.addEventListener('pointerup', () => this.resizing = false);
      document.addEventListener('pointerleave', () => this.resizing = false);

      ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventType => {
          this.imageContainer.addEventListener(eventType, (event) => {
              event.preventDefault();
              event.stopPropagation();
          }, false);
      });

      this.imageContainer.addEventListener('dragenter', () => {
          this.imageElement.style.cursor = 'copy';
          this.drawingCanvas.style.cursor = 'copy';
      });

      this.imageContainer.addEventListener('dragleave', () => {
          this.imageElement.style.cursor = '';
          this.drawingCanvas.style.cursor = '';
      });

      this.imageContainer.addEventListener('drop', (event) => {
          this.imageElement.style.cursor = '';
          this.drawingCanvas.style.cursor = '';

          const dataTransfer = event.dataTransfer;
          const files = dataTransfer.files;
          if (files.length > 0) {
              this.handleFileUpload(files[0]);
          }
      });

      this.imageContainer.addEventListener('pointerenter', () => this.pointerInsideContainer = true);
      this.imageContainer.addEventListener('pointerleave', () => this.pointerInsideContainer = false);

      document.addEventListener('paste', (event) => {
          event.preventDefault();
          event.stopPropagation();
          this.handlePaste(event);
      });

      document.addEventListener('keydown', (event) => {
          if (event.ctrlKey && event.key === 'z') {
              event.preventDefault();
              this.undo();
          } else if (event.ctrlKey && event.key === 'y') {
              event.preventDefault();
              this.redo();
          }
      });
  }

  initializeUndoRedoButtons() {
      this.updateUndoRedoButtons();
  }

  listenForBackgroundAndForegroundChanges() {
      this.backgroundGradioBind.listen((base64Data) => this.uploadBase64(base64Data));
      this.foregroundGradioBind.listen((base64Data) => this.uploadBase64DrawingCanvas(base64Data));
  }

  /**
   * Handles drawing on the canvas.
   * @param {PointerEvent} event - The pointer event.
   */
  handleDraw(event) {
      const context = this.drawingCanvas.getContext('2d');
      const rect = this.drawingCanvas.getBoundingClientRect();
      const x = (event.clientX - rect.left) / this.imgScale;
      const y = (event.clientY - rect.top) / this.imgScale;

      this.tempDrawPoints.push([x, y]);
      context.putImageData(this.tempDrawBackground, 0, 0);
      this.drawingPath = new Path2D();
      this.drawingPath.moveTo(this.tempDrawPoints[0][0], this.tempDrawPoints[0][1]);

      for (let i = 1; i < this.tempDrawPoints.length; i++) {
          this.drawingPath.lineTo(this.tempDrawPoints[i][0], this.tempDrawPoints[i][1]);
      }

      context.lineCap = 'round';
      context.lineJoin = 'round';
      context.lineWidth = (this.scribbleWidth / this.imgScale) * 20;

      if (this.contrastScribbles) {
          this.applyContrastScribbles(context);
          return;
      }

      context.strokeStyle = this.scribbleColor;

      if (this.scribbleAlpha <= 0) {
          this.applyEraser(context);
          return;
      }

      context.globalCompositeOperation = 'source-over';

      if (this.scribbleSoftness <= 0) {
          this.applySolidScribbles(context);
          return;
      }

      this.applySoftScribbles(context);
  }

  applyContrastScribbles(context) {
      context.strokeStyle = this.contrastPattern;
      context.stroke(this.drawingPath);
  }

  applyEraser(context) {
      context.globalCompositeOperation = 'destination-out';
      context.globalAlpha = 1;
      context.stroke(this.drawingPath);
  }

  applySolidScribbles(context) {
      context.globalAlpha = this.scribbleAlpha / 100;
      context.stroke(this.drawingPath);
  }

  applySoftScribbles(context) {
      const minLineWidth = context.lineWidth * (1 - this.scribbleSoftness / 150);
      const maxLineWidth = context.lineWidth * (1 + this.scribbleSoftness / 150);
      const steps = Math.round(5 + this.scribbleSoftness / 5);
      const lineWidthIncrement = (maxLineWidth - minLineWidth) / (steps - 1);

      context.globalAlpha = 1 - Math.pow(1 - Math.min(this.scribbleAlpha / 100, 0.95), 1 / steps);

      for (let i = 0; i < steps; i++) {
          context.lineWidth = minLineWidth + lineWidthIncrement * i;
          context.stroke(this.drawingPath);
      }
  }

  /**
   * Handles file uploads.
   * @param {File} file - The uploaded file.
   */
  handleFileUpload(file) {
      if (file && !this.noUpload) {
          const reader = new FileReader();
          reader.onload = (event) => {
              this.uploadBase64(event.target.result);
          };
          reader.readAsDataURL(file);
      }
  }

  /**
   * Handles paste events
   * @param {ClipboardEvent} event - The paste event.
   */
  handlePaste(event) {
      const items = event.clipboardData.items;
      for (let i = 0; i < items.length; i++) {
          const item = items[i];
          if (item.type.indexOf('image') !== -1) {
              const file = item.getAsFile();
              this.handleFileUpload(file);
              break;
          }
      }
  }

  /**
   * Uploads a base64 image to the background binding.
   * @param {string} base64Data - The base64 image data.
   */
  uploadBase64(base64Data) {
      if (this.gradioConfig && !this.gradioConfig.version.startsWith('4')) return;
      if (!this.gradioConfig) return;

      const img = new Image();
      img.onload = () => this.onImageLoad(img, base64Data);

      if (base64Data) {
          img.src = base64Data;
      } else {
          this.clearImage();
      }
  }

  onImageLoad(img, base64Data) {
      this.img = base64Data;
      this.originalWidth = img.width;
      this.originalHeight = img.height;

      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      if (drawingCanvas.width !== img.width || drawingCanvas.height !== img.height) {
          drawingCanvas.width = img.width;
          drawingCanvas.height = img.height;
      }

      this.adjustInitialPositionAndScale();
      this.drawImage();
      this.onImageUpload();
      this.saveState();

      document.getElementById(`imageInput_${this.uuid}`).value = null;
      document.getElementById(`uploadHint_${this.uuid}`).style.display = 'none';
  }

  clearImage() {
      this.img = null;
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      drawingCanvas.width = 1;
      drawingCanvas.height = 1;
      this.adjustInitialPositionAndScale();
      this.drawImage();
      this.onImageUpload();
      this.saveState();
  }

  /**
   * Uploads the drawing canvas as a base64 image to the foreground binding.
   * @param {string} base64Data - The base64 image data.
   */
  uploadBase64DrawingCanvas(base64Data) {
      const img = new Image();
      img.onload = () => this.onDrawingCanvasLoad(img);

      if (base64Data) {
          img.src = base64Data;
      } else {
          this.clearDrawingCanvas();
      }
  }

  onDrawingCanvasLoad(img) {
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      const context = drawingCanvas.getContext('2d');
      context.clearRect(0, 0, drawingCanvas.width, drawingCanvas.height);
      context.drawImage(img, 0, 0);
      this.saveState();
  }

  clearDrawingCanvas() {
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      const context = drawingCanvas.getContext('2d');
      context.clearRect(0, 0, drawingCanvas.width, drawingCanvas.height);
      this.saveState();
  }

  /**
   * Checks if the given coordinates are inside the image.
   * @param {number} x - The x-coordinate.
   * @param {number} y - The y-coordinate.
   * @returns {boolean} - True if inside the image, else false.
   */
  isInsideImage(x, y) {
      const scaledWidth = this.originalWidth * this.imgScale;
      const scaledHeight = this.originalHeight * this.imgScale;
      return (
          x > this.imgX &&
          x < this.imgX + scaledWidth &&
          y > this.imgY &&
          y < this.imgY + scaledHeight
      );
  }

  /**
   * Draws the image and updates the canvas.
   */
  drawImage() {
      const imageElement = document.getElementById(`image_${this.uuid}`);
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);

      if (this.img) {
          const scaledWidth = this.originalWidth * this.imgScale;
          const scaledHeight = this.originalHeight * this.imgScale;

          imageElement.src = this.img;
          imageElement.style.width = `${scaledWidth}px`;
          imageElement.style.height = `${scaledHeight}px`;
          imageElement.style.left = `${this.imgX}px`;
          imageElement.style.top = `${this.imgY}px`;
          imageElement.style.display = 'block';

          drawingCanvas.style.width = `${scaledWidth}px`;
          drawingCanvas.style.height = `${scaledHeight}px`;
          drawingCanvas.style.left = `${this.imgX}px`;
          drawingCanvas.style.top = `${this.imgY}px`;
      } else {
          imageElement.src = '';
          imageElement.style.display = 'none';
      }
  }

  /**
   * Adjusts the initial position and scale of the image to fit the container.
   */
  adjustInitialPositionAndScale() {
      const imageContainer = document.getElementById(`imageContainer_${this.uuid}`);
      const containerWidth = imageContainer.clientWidth - 20;
      const containerHeight = imageContainer.clientHeight - 20;

      const scaleX = containerWidth / this.originalWidth;
      const scaleY = containerHeight / this.originalHeight;
      this.imgScale = Math.min(scaleX, scaleY);

      const scaledWidth = this.originalWidth * this.imgScale;
      const scaledHeight = this.originalHeight * this.imgScale;

      this.imgX = (imageContainer.clientWidth - scaledWidth) / 2;
      this.imgY = (imageContainer.clientHeight - scaledHeight) / 2;
  }

  /**
   * Resets the image to its initial state.
   */
  resetImage() {
      this.clearDrawingCanvas();
      this.adjustInitialPositionAndScale();
      this.drawImage();
      this.saveState();
  }

  /**
   * Removes the current image from the canvas.
   */
  removeImage() {
      this.img = null;
      this.clearDrawingCanvas();
      this.clearImageElement();
      this.saveState();

      if (!this.noUpload) {
          document.getElementById(`uploadHint_${this.uuid}`).style.display = 'block';
      }

      this.onImageUpload();
  }

  clearImageElement() {
      const imageElement = document.getElementById(`image_${this.uuid}`);
      imageElement.src = '';
      imageElement.style.width = '0';
      imageElement.style.height = '0';
  }

  /**
   * Saves the current state for undo/redo functionality.
   */
  saveState() {
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      const context = drawingCanvas.getContext('2d');
      const imageData = context.getImageData(0, 0, drawingCanvas.width, drawingCanvas.height);

      this.history = this.history.slice(0, this.historyIndex + 1);
      this.history.push(imageData);
      this.historyIndex++;
      this.updateUndoRedoButtons();
      this.onDrawingCanvasUpload();
  }

  /**
   * Undoes the last action.
   */
  undo() {
      if (this.historyIndex > 0) {
          this.historyIndex--;
          this.restoreState();
          this.updateUndoRedoButtons();
      }
  }

  /**
   * Redoes the last undone action.
   */
  redo() {
      if (this.historyIndex < this.history.length - 1) {
          this.historyIndex++;
          this.restoreState();
          this.updateUndoRedoButtons();
      }
  }

  /**
   * Restores the canvas to a previous state.
   */
  restoreState() {
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      const context = drawingCanvas.getContext('2d');
      const imageData = this.history[this.historyIndex];

      context.putImageData(imageData, 0, 0);
      this.onDrawingCanvasUpload();
  }

  /**
   * Updates the state of undo and redo buttons.
   */
  updateUndoRedoButtons() {
      const undoButton = document.getElementById(`undoButton_${this.uuid}`);
      const redoButton = document.getElementById(`redoButton_${this.uuid}`);

      undoButton.disabled = this.historyIndex <= 0;
      redoButton.disabled = this.historyIndex >= this.history.length - 1;

      undoButton.style.opacity = undoButton.disabled ? '0.5' : '1';
      redoButton.style.opacity = redoButton.disabled ? '0.5' : '1';
  }

  /**
   * Called when an image is uploaded.
   */
  onImageUpload() {
      if (!this.img) {
          this.backgroundGradioBind.setValue('');
          return;
      }

      const imageElement = document.getElementById(`image_${this.uuid}`);
      const tempCanvas = this.tempCanvas;
      const context = tempCanvas.getContext('2d');

      tempCanvas.width = this.originalWidth;
      tempCanvas.height = this.originalHeight;
      context.drawImage(imageElement, 0, 0, this.originalWidth, this.originalHeight);

      const base64Data = tempCanvas.toDataURL('image/png');
      this.backgroundGradioBind.setValue(base64Data);
  }

  /**
   * Called when the drawing canvas is updated.
   */
  onDrawingCanvasUpload() {
      if (!this.img) {
          this.foregroundGradioBind.setValue('');
          return;
      }

      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);
      const base64Data = drawingCanvas.toDataURL('image/png');
      this.foregroundGradioBind.setValue(base64Data);
  }

  /**
   * Maximizes the canvas container.
   */
  maximize() {
      if (this.maximized) return;

      this.saveOriginalState();
      this.applyMaximizedStyles();
      this.maximized = true;
  }

  saveOriginalState() {
      const container = document.getElementById(`container_${this.uuid}`);
      this.originalState = {
          width: container.style.width,
          height: container.style.height,
          top: container.style.top,
          left: container.style.left,
          position: container.style.position,
          zIndex: container.style.zIndex,
      };
  }

  applyMaximizedStyles() {
      const container = document.getElementById(`container_${this.uuid}`);
      const maxButton = document.getElementById(`maxButton_${this.uuid}`);
      const minButton = document.getElementById(`minButton_${this.uuid}`);

      container.style.width = '100vw';
      container.style.height = '100vh';
      container.style.top = '0';
      container.style.left = '0';
      container.style.position = 'fixed';
      container.style.zIndex = '1000';

      maxButton.style.display = 'none';
      minButton.style.display = 'inline-block';
  }

  /**
   * Restores the canvas container to its original size.
   */
  minimize() {
      if (!this.maximized) return;

      this.restoreOriginalState();
      this.maximized = false;
  }

  restoreOriginalState() {
      const container = document.getElementById(`container_${this.uuid}`);
      const maxButton = document.getElementById(`maxButton_${this.uuid}`);
      const minButton = document.getElementById(`minButton_${this.uuid}`);

      container.style.width = this.originalState.width;
      container.style.height = this.originalState.height;
      container.style.top = this.originalState.top;
      container.style.left = this.originalState.left;
      container.style.position = this.originalState.position;
      container.style.zIndex = this.originalState.zIndex;

      maxButton.style.display = 'inline-block';
      minButton.style.display = 'none';
  }

  /**
   * Handles the end of a drag event.
   * @param {PointerEvent} event - The pointer event.
   * @param {boolean} isLeaving - Whether the pointer is leaving the container.
   */
  handleDragEnd(event, isLeaving) {
      this.dragging = false;
      const imageElement = document.getElementById(`image_${this.uuid}`);
      const drawingCanvas = document.getElementById(`drawingCanvas_${this.uuid}`);

      imageElement.style.cursor = 'grab';
      drawingCanvas.style.cursor = 'grab';
  }
}

// Constants
const True = true;
const False = false;

/**
* Usage Example:
* 
* // Assuming you have the following HTML structure:
* 
* <div id="container_UUID" class="container">
*   <div id="toolbar_UUID" class="toolbar">
*     <button id="uploadButton_UUID">Upload</button>
*     <button id="resetButton_UUID">Reset</button>
*     <button id="centerButton_UUID">Center</button>
*     <button id="removeButton_UUID">Remove</button>
*     <button id="undoButton_UUID" disabled>Undo</button>
*     <button id="redoButton_UUID" disabled>Redo</button>
*     <button id="maxButton_UUID">Maximize</button>
*     <button id="minButton_UUID" style="display:none;">Minimize</button>
*     <!-- Add other toolbar elements as needed -->
*   </div>
*   <div id="imageContainer_UUID" class="image-container">
*     <img id="image_UUID" class="image" src="" alt="Canvas Image" />
*     <canvas id="drawingCanvas_UUID" class="drawing-canvas"></canvas>
*     <div id="resizeLine_UUID" class="resize-line"></div>
*     <div id="scribbleIndicator_UUID" class="scribble-indicator"></div>
*     <input type="file" id="imageInput_UUID" accept="image/*" style="display:none;" />
*     <div id="uploadHint_UUID" class="upload-hint">Drag & Drop an image here or click to upload.</div>
*     <!-- Add other elements as needed -->
*   </div>
* </div>
* 
* // Initialize the ForgeCanvas
* const canvas = new ForgeCanvas(
*   'UUID',            // Unique identifier
*   false,             // noUpload
*   false,             // noScribbles
*   false,             // contrastScribbles
*   512,               // initialHeight
*   '#000000',         // scribbleColor
*   false,             // scribbleColorFixed
*   4,                 // scribbleWidth
*   false,             // scribbleWidthFixed
*   100,               // scribbleAlpha
*   false,             // scribbleAlphaFixed
*   0,                 // scribbleSoftness
*   false              // scribbleSoftnessFixed
* );
*/
